mapper.sql:
and a.store_id = #{store_id}
and (a.id=#{title} or a.living_theme like concat('%',#{title},'%'))
and a.living_status=#{status}
and (a.user_id=#{userId} or b.user_name like concat ('%',#{userId},'%'))
and a.start_time   >=   #{startTime}
and a.start_time   <=   #{endTime}

and o.otype = 'ZB'
and d.living_room_id=#{roomId}
 and o.store_id = #{store_id} and lu.store_id = #{store_id}

    and o.recycle=#{recycle}
    and o.recycle != 1

and o.status = #{status}
and (o.sNo like concat('%',#{sNo},'%') or lu.user_name like concat('%',#{sNo},'%') or
    o.mobile like concat('%',#{sNo},'%') or o.user_id like concat('%',#{sNo},'%') or o.p_sno like
    concat('%',#{sNo},'%') )

and d.anchor_id=#{anchor}
and m.name like concat('%',#{mch_name},'%')
and o.add_time   >=   #{startdate}
and o.add_time   <=   #{enddate}

mapper.select:
select b.*,date_format(a.add_time,'%Y-%m-%d %H:%i:%s') as follow_time from lkt_living_follow_list a
left join lkt_user b on a.user_id = b.user_id
where 1=1 and a.recycle=0
and a.store_id=#{store_id}
and a.anchor_id=#{anchor_id}
and (b.user_name like concat('%',#{key},'%') or b.mobile = #{key} or b.user_id like concat('%',#{key},'%') or b.zhanghao like concat('%',#{key},'%'))
and a.add_time   >=   #{startDate}
and a.add_time   <=   #{endDate}
order by a.add_time
limit #{pageStart},#{pageEnd}

select count(1) from lkt_living_follow_list a
left join lkt_user b on a.user_id = b.user_id
where 1=1 and a.recycle=0
and a.store_id=#{store_id}
and a.anchor_id=#{anchor_id}
and (b.user_name like concat('%',#{key},'%') or b.mobile = #{key} or b.user_id like concat('%',#{key},'%') or b.zhanghao like concat('%',#{key},'%'))
and a.add_time   >=   #{startDate}
and a.add_time   <=   #{endDate}

sql.trim:
a.store_id = #{store_id} and a.recycle=0 and a.oType='ZB' and d.living_room_id=#{room_id}


        #{status,jdbcType=INTEGER}


and a.add_time   >=   #{startTime}
and a.add_time   <=   #{endTime}
and (a.sNo like concat('%',#{keyWord},'%') or m.name like concat('%',#{keyWord},'%') or u.user_name like concat('%',#{keyWord},'%'))

mapper.select:
select a.*,r.id as roomId,r.living_theme as title,m.name as mch_name,m.head_img as headimgurl,d.commission from lkt_order a left JOIN lkt_order_details d ON a.sNo = d.r_sNo LEFT JOIN lkt_product_list as p on p.id = d.p_id left join lkt_living_room r on d.living_room_id = r.id left join lkt_mch m on m.id = p.mch_id left join lkt_user u on u.user_id = a.user_id
order by add_time desc
limit #{pageNo},#{pageSize}

select a.*,u.user_name,u.headimgurl as user_url,u.fans_num from lkt_living_room a left join lkt_user u on a.user_id = u.user_id





order by ${sort}

    limit #{pageNo},#{pageSize}

select u.user_id,u.user_name,u.mobile,r.money,date_format(r.add_date,'%Y-%m-%d %H:%i:%s') as add_date from lkt_record r
left join lkt_user u on r.user_id=u.user_id
where r.type=42 and r.store_id=#{store_id}
and (u.id=#{keyWord} or u.user_id= #{keyWord} or u.user_name like concat ('%',#{keyWord},'%') or u.mobile=#{keyWord})
and r.add_date   >=   #{start_time}
and r.add_date   <=   #{end_time}
order by r.add_date desc
limit #{pageNo},#{pageSize}

select count(1) from lkt_record r
left join lkt_user u on r.user_id=u.user_id
where r.type=42 and r.store_id=#{store_id}
and (u.id=#{keyWord} or u.user_id= #{keyWord} or u.user_name like concat ('%',#{keyWord},'%') or u.mobile=#{keyWord})
and r.add_date   >=   #{start_time}
and r.add_date   <=   #{end_time}
